#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long D; scanf("%lld",&D);
        if(D%2){
            printf("-1\n");
        }else{
            long long h = D/2;
            printf("0 %lld\n",h);
            printf("%lld 0\n",h);
            printf("0 %lld\n",-h);
            printf("%lld 0\n",-h);
        }
    }
    return 0;
}

