#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        D = int(next(it))
        if D % 2:
            out.append("-1")
        else:
            h = D // 2
            out.append(f"0 {h}")
            out.append(f"{h} 0")
            out.append(f"0 {-h}")
            out.append(f"{-h} 0")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

